-- =============================================
-- CCFT Study App — Vocab Terms Table
-- Central "brain" for all extracted terms
-- Readable by all authenticated users
-- =============================================

create table public.vocab_terms (
  id         uuid primary key default gen_random_uuid(),
  term       text not null unique,
  definition text not null,
  source     text not null,
  domains    text[] not null,
  created_at timestamptz not null default now()
);

alter table public.vocab_terms enable row level security;

-- All authenticated users can read all terms
create policy "Authenticated users can read vocab terms"
  on public.vocab_terms
  for select
  using (auth.role() = 'authenticated');

create index idx_vocab_terms_term on public.vocab_terms(term);
create index idx_vocab_terms_domains on public.vocab_terms using gin(domains);

-- =============================================
-- SEED: 120 terms from top 10 priority docs
-- =============================================

on conflict (term) do nothing;
